const accessToken = $json.accessToken;
const userId = $json.userId;
if (!accessToken) throw new Error('No accessToken passed from Load Tokens node');
const nonce = Date.now();
const requestId = md5(md5(nonce.toString()));
const params = {family_member_id: userId, nonce: nonce};
// GET requests use sorted key=value params
const sortedParamsStr = Object.entries(params)
  .sort(([a],[b]) => a.localeCompare(b))
  .map(([k,v]) => k + '=' + v)
  .join('&');
const SIGNING_SECRET = 'wyze_app_secret_key_132';
const signingKeyStr = md5(accessToken + SIGNING_SECRET);
const signature2 = hmacMd5(signingKeyStr, sortedParamsStr);
return [{json:{accessToken,userId,nonce:nonce.toString(),requestId,signature2,family_member_id:userId}}];

const scaleResponse = $input.first().json;

// Get today's date in local time (YYYY-MM-DD)
const today = new Date();
const todayStr = today.getFullYear() + '-' +
  String(today.getMonth() + 1).padStart(2, '0') + '-' +
  String(today.getDate()).padStart(2, '0');

// Extract record — get_latest_record returns { code, msg, data: { ... } } or { code, msg, data: [{...}] }
let record = null;
if (scaleResponse.data) {
  if (Array.isArray(scaleResponse.data)) {
    record = scaleResponse.data[0];
  } else if (typeof scaleResponse.data === 'object' && scaleResponse.data !== null) {
    record = scaleResponse.data;
  }
}

if (!record || (!record.weight && record.weight !== 0)) {
  return [{
    json: {
      shouldLog: false,
      reason: 'No valid weight record found. Check scale service endpoint or try get_record_range.',
      rawResponse: scaleResponse
    }
  }];
}

// measure_ts is epoch in milliseconds
const measureTs = record.measure_ts;
if (!measureTs) {
  return [{
    json: {
      shouldLog: false,
      reason: 'Record missing measure_ts: ' + JSON.stringify(record)
    }
  }];
}

// Convert epoch ms to local date string
const recordDate = new Date(measureTs);
const recordDateStr = recordDate.getFullYear() + '-' +
  String(recordDate.getMonth() + 1).padStart(2, '0') + '-' +
  String(recordDate.getDate()).padStart(2, '0');

// Skip if the latest measurement isn't from today
if (recordDateStr !== todayStr) {
  return [{
    json: {
      shouldLog: false,
      reason: `Latest measurement was ${recordDateStr}, not today (${todayStr}). Step on the scale first!`,
      recordDateStr,
      todayStr
    }
  }];
}

// Weight: raw API returns kg, convert to lbs and round to whole number
const weightKg = parseFloat(record.weight);
const weightLbs = Math.round(weightKg * 2.20462262185);

// Body fat % (null if not measured)
let bodyFat = '';
if (record.body_fat !== null && record.body_fat !== undefined && record.body_fat !== 0) {
  bodyFat = parseFloat(record.body_fat).toFixed(1);
}

// Format new markdown table row
const newRow = `| ${todayStr} | ${weightLbs} | ${bodyFat} | |`;

return [{
  json: {
    shouldLog: true,
    todayStr,
    weightLbs,
    bodyFat,
    newRow,
    measureTs,
    rawRecord: record
  }
}];

const processedData = $('Parse & Check').first().json;
const githubData = $input.first().json;

// Decode base64 content from GitHub API response
// GitHub wraps content in base64 with \n every 60 chars
const currentContent = Buffer.from(
  githubData.content.replace(/\n/g, ''),
  'base64'
).toString('utf-8');

const sha = githubData.sha;

// Append new row before trailing whitespace
const trimmedContent = currentContent.trimEnd();
const newContent = trimmedContent + '\n' + processedData.newRow + '\n';

// Encode back to base64 for GitHub API PUT
const newContentBase64 = Buffer.from(newContent, 'utf-8').toString('base64');

return [{
  json: {
    sha,
    newContentBase64,
    commitMessage: `chore: auto-log weight ${processedData.todayStr} — ${processedData.weightLbs} lbs`,
    todayStr: processedData.todayStr,
    weightLbs: processedData.weightLbs,
    bodyFat: processedData.bodyFat
  }
}];

// Persist the measure_ts so re-runs today don't double-log
const staticData = $getWorkflowStaticData('global');
staticData.lastLoggedTs = $('Parse & Check').first().json.measure_ts;

return [{ json: {
  success: true,
  logged: true,
  weightLbs: $('Build Updated File').first().json.weightLbs,
  date: $('Build Updated File').first().json.todayStr
} }];
